// Validation helpers
function isValidIndexName(index) {
  if (!index || typeof index !== 'string') return false;
  if (index.length > 255) return false;
  // Allow alphanumeric, hyphens, underscores, dots, and wildcards for pattern matching
  const validPattern = /^[a-zA-Z0-9_\-.*]+$/;
  if (!validPattern.test(index)) return false;
  // Prevent path traversal
  if (index.includes('..')) return false;
  return true;
}

function isSystemIndex(index) {
  // Block access to Elasticsearch system/internal indices
  const blockedPrefixes = ['.security', '.kibana', '.apm', '.tasks', '.async-search', '.monitoring'];
  const lowerIndex = index.toLowerCase();
  return blockedPrefixes.some(prefix => lowerIndex.startsWith(prefix));
}

